const html = $input.first().json.html;
const meta = {
  course_id:        $input.first().json.course_id,
  target_course_id: $input.first().json.target_course_id,
  source_language:  $input.first().json.source_language,
  target_language:  $input.first().json.target_language,
  enabled_modules:  $input.first().json.enabled_modules || []
};

const CHUNK_THRESHOLD = 12000;

function estimateTokens(html) {
  const plain = html.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
  return Math.ceil(plain.split(' ').filter(w => w).length * 1.3);
}

// Find all h2 and h3 positions in the merged HTML
const tagRegex = /<(h2|h3)(?:\s[^>]*)?>[\s\S]*?<\/\1>/gi;
const tagMatches = [];
let m;
while ((m = tagRegex.exec(html)) !== null) {
  const tag = m[1].toLowerCase();
  const nameMatch = m[0].match(/<(?:h2|h3)[^>]*>([\s\S]*?)<\/(?:h2|h3)>/i);
  const name = nameMatch ? nameMatch[1].replace(/<[^>]+>/g, '').trim() : '';
  tagMatches.push({ index: m.index, end: m.index + m[0].length, tag, name });
}

const chapters = [];
let chapterIndex = 0;
let partIndex   = 0;
let partName    = '';

// Content before first tag = P0C0 intro
if (tagMatches.length > 0 && tagMatches[0].index > 50) {
  const introHtml = html.slice(0, tagMatches[0].index).trim();
  if (introHtml.length > 50) {
    chapterIndex++;
    chapters.push({ ...meta, chapter_index: 0, chapter_name: 'Course Introduction',
      part_name: '', part_index: 0, is_intro: true,
      html: introHtml, token_estimate: estimateTokens(introHtml),
      needs_chunking: false });
  }
}

for (let i = 0; i < tagMatches.length; i++) {
  const curr = tagMatches[i];
  const next = tagMatches[i + 1];
  if (curr.tag === 'h2') { partName = curr.name; partIndex++; continue; }
  // h3 = chapter
  const contentEnd = next ? next.index : html.length;
  const chapterHtml = html.slice(curr.index, contentEnd).trim();
  const tokens = estimateTokens(chapterHtml);
  chapterIndex++;
  chapters.push({ ...meta,
    chapter_index: chapterIndex, chapter_name: curr.name,
    part_name: partName, part_index: partIndex, is_intro: false,
    html: chapterHtml, token_estimate: tokens,
    needs_chunking: tokens > CHUNK_THRESHOLD });
}

return chapters.map(c => ({ json: c }));

const THRESHOLD    = 12000;
const CTX_CHARS    = 300;
const ATOMIC       = ['aside','ul','ol','table','figure','pre'];

function estimateTokens(html) {
  const plain = html.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
  return Math.ceil(plain.split(' ').filter(w=>w).length * 1.3);
}

function insideAtomic(html, pos) {
  const before = html.slice(0, pos);
  return ATOMIC.some(tag => {
    const opens  = (before.match(new RegExp(`<${tag}[\\s>]`, 'gi')) || []).length;
    const closes = (before.match(new RegExp(`<\\/${tag}>`,  'gi')) || []).length;
    return opens > closes;
  });
}

function findSplitPoints(html) {
  const pts = [];
  // Priority 1 — before <h4>
  const h4 = /<h4[\s>]/gi; let m;
  while ((m = h4.exec(html)) !== null)
    if (m.index > 0 && !insideAtomic(html, m.index))
      pts.push({ index: m.index, p: 1 });
  // Priority 3 — </p> immediately before <figure>
  if (!pts.length) {
    const pf = /<\/p>(\s*)<figure/gi;
    while ((m = pf.exec(html)) !== null)
      if (!insideAtomic(html, m.index))
        pts.push({ index: m.index + 4, p: 3 });
  }
  return pts.sort((a,b) => a.index - b.index);
}

function chunkChapter(ch) {
  const html = ch.html;
  const pts  = findSplitPoints(html);
  if (!pts.length) return [{ ...ch, chunk_index:1, total_chunks:1,
    preceding_context:'', was_chunked:false,
    split_warning:'No safe split point found — sent as single chunk' }];

  const chunks = []; let start = 0; let idx = 1;
  for (let i = 0; i < pts.length; i++) {
    const segHtml = html.slice(start, pts[i].index);
    if (estimateTokens(segHtml) >= THRESHOLD || i === pts.length - 1) {
      chunks.push({ ...ch, html: segHtml, chunk_index: idx,
        preceding_context: start > 0 ? html.slice(Math.max(0,start-CTX_CHARS),start) : '',
        token_estimate: estimateTokens(segHtml), was_chunked: true });
      start = pts[i].index; idx++;
    }
  }
  if (start < html.length) {
    const segHtml = html.slice(start);
    chunks.push({ ...ch, html: segHtml, chunk_index: idx,
      preceding_context: html.slice(Math.max(0,start-CTX_CHARS),start),
      token_estimate: estimateTokens(segHtml), was_chunked: true });
  }
  const total = idx;
  return chunks.map(c => ({ ...c, total_chunks: total }));
}

const output = [];
for (const item of $input.all()) {
  const ch = item.json;
  if (ch.needs_chunking) {
    chunkChapter(ch).forEach(c => output.push({ json: c }));
  } else {
    output.push({ json: { ...ch, chunk_index:1, total_chunks:1,
      preceding_context:'', was_chunked:false }});
  }
}
return output;

const chunks = $input.all();
const total_chunks   = chunks.length;
const chunked_chaps  = chunks.filter(c => c.json.was_chunked).length;
const total_tokens   = chunks.reduce((s,c) => s + (c.json.token_estimate||0), 0);

// Add summary metadata to every chunk
return chunks.map(c => ({ json: {
  ...c.json,
  pipeline_meta: {
    total_chunks,
    chunked_chapters: chunked_chaps,
    estimated_total_tokens: total_tokens,
    preprocessor_version: 'v3.0'
  }
}}));

